import numpy as np

# New algorithm description: {Select the next customer by evaluating potential routes using a simulated annealing-inspired approach that slightly favors shorter dynamic detours, accounts for time window violations, and balances the overall workload among trucks.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(position1, position2):
        return np.linalg.norm(position1 - position2) / truck_speed

    def score_customer(candidate_index):
        candidate_pos = unvisited_customers[candidate_index]
        travel_time = calculate_travel_time(cur_truck_pos, candidate_pos)
        arrival_time = current_time + travel_time
        start_time, end_time = time_windows[candidate_index]

        if arrival_time <= start_time:
            waiting_time = start_time - arrival_time
            time_penalty = waiting_time * 1.5
        elif arrival_time > start_time and arrival_time <= end_time:
            waiting_time = 0
            time_penalty = 0
        else:
            waiting_time = 0
            time_penalty = np.inf

        depot_return_time = calculate_travel_time(candidate_pos, depot_pos)
        balance_penalty = np.std([calculate_travel_time(pos, depot_pos) for pos in all_truck_pos]) 

        return -(travel_time + time_penalty + balance_penalty - depot_return_time * 0.1)

    best_score = -np.inf
    best_node = None
    for index in range(len(unvisited_customers)):
        score = score_customer(index)
        if score > best_score or (score == best_score and np.random.uniform(0, 1) < 0.1):
            best_score = score
            best_node = index

    return best_node
